    typealias SwiftType = Event

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> Event {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .paymentSuccessful(paymentId: try FfiConverterTypePaymentId.read(from: &buf), paymentHash: try FfiConverterData.read(from: &buf), paymentPreimage: try FfiConverterData.read(from: &buf), feePaidMsat: try FfiConverterOptionUInt64.read(from: &buf)
        )
        
        case 2: return .paymentFailed(paymentId: try FfiConverterTypePaymentId.read(from: &buf), paymentHash: try FfiConverterOptionData.read(from: &buf), reason: try FfiConverterOptionString.read(from: &buf)
        )
        
        case 3: return .paymentReceived(paymentId: try FfiConverterTypePaymentId.read(from: &buf), paymentHash: try FfiConverterData.read(from: &buf), amountMsat: try FfiConverterUInt64.read(from: &buf), customRecords: try FfiConverterSequenceData.read(from: &buf), lspFeeMsats: try FfiConverterOptionUInt64.read(from: &buf)
