        case 4: return .onchainPaymentReceived(paymentId: try FfiConverterTypePaymentId.read(from: &buf), txid: try FfiConverterData.read(from: &buf), amountSat: try FfiConverterUInt64.read(from: &buf)
        )
        
        case 5: return .channelOpened(channelId: try FfiConverterData.read(from: &buf), userChannelId: try FfiConverterData.read(from: &buf), counterpartyNodeId: try FfiConverterData.read(from: &buf), fundingTxo: try FfiConverterString.read(from: &buf)
        )
        
        case 6: return .channelClosed(channelId: try FfiConverterData.read(from: &buf), userChannelId: try FfiConverterData.read(from: &buf), counterpartyNodeId: try FfiConverterData.read(from: &buf), reason: try FfiConverterOptionString.read(from: &buf)
        )
        
        case 7: return .rebalanceInitiated(triggerPaymentId: try FfiConverterTypePaymentId.read(from: &buf), trustedRebalancePaymentId: try FfiConverterData.read(from: &buf), amountMsat: try FfiConverterUInt64.read(from: &buf)
        )
        
        case 8: return .rebalanceSuccessful(triggerPaymentId: try FfiConverterTypePaymentId.read(from: &buf), trustedRebalancePaymentId: try FfiConverterData.read(from: &buf), lnRebalancePaymentId: try FfiConverterData.read(from: &buf), amountMsat: try FfiConverterUInt64.read(from: &buf), feeMsat: try FfiConverterUInt64.read(from: &buf)
        )
        
        case 9: return .splicePending(channelId: try FfiConverterData.read(from: &buf), userChannelId: try FfiConverterData.read(from: &buf), counterpartyNodeId: try FfiConverterData.read(from: &buf), newFundingTxo: try FfiConverterString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: Event, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .paymentSuccessful(paymentId,paymentHash,paymentPreimage,feePaidMsat):
            writeInt(&buf, Int32(1))
            FfiConverterTypePaymentId.write(paymentId, into: &buf)
            FfiConverterData.write(paymentHash, into: &buf)
            FfiConverterData.write(paymentPreimage, into: &buf)
            FfiConverterOptionUInt64.write(feePaidMsat, into: &buf)
            
        
        case let .paymentFailed(paymentId,paymentHash,reason):
            writeInt(&buf, Int32(2))
            FfiConverterTypePaymentId.write(paymentId, into: &buf)
            FfiConverterOptionData.write(paymentHash, into: &buf)
            FfiConverterOptionString.write(reason, into: &buf)
            
        
        case let .paymentReceived(paymentId,paymentHash,amountMsat,customRecords,lspFeeMsats):
            writeInt(&buf, Int32(3))
            FfiConverterTypePaymentId.write(paymentId, into: &buf)
            FfiConverterData.write(paymentHash, into: &buf)
            FfiConverterUInt64.write(amountMsat, into: &buf)
            FfiConverterSequenceData.write(customRecords, into: &buf)
            FfiConverterOptionUInt64.write(lspFeeMsats, into: &buf)
            
        
        case let .onchainPaymentReceived(paymentId,txid,amountSat):
            writeInt(&buf, Int32(4))
            FfiConverterTypePaymentId.write(paymentId, into: &buf)
            FfiConverterData.write(txid, into: &buf)
            FfiConverterUInt64.write(amountSat, into: &buf)
            
        
        case let .channelOpened(channelId,userChannelId,counterpartyNodeId,fundingTxo):
            writeInt(&buf, Int32(5))
            FfiConverterData.write(channelId, into: &buf)
            FfiConverterData.write(userChannelId, into: &buf)
            FfiConverterData.write(counterpartyNodeId, into: &buf)
            FfiConverterString.write(fundingTxo, into: &buf)
            
        
        case let .channelClosed(channelId,userChannelId,counterpartyNodeId,reason):
            writeInt(&buf, Int32(6))
            FfiConverterData.write(channelId, into: &buf)
            FfiConverterData.write(userChannelId, into: &buf)
            FfiConverterData.write(counterpartyNodeId, into: &buf)
            FfiConverterOptionString.write(reason, into: &buf)
            
        
        case let .rebalanceInitiated(triggerPaymentId,trustedRebalancePaymentId,amountMsat):
            writeInt(&buf, Int32(7))
            FfiConverterTypePaymentId.write(triggerPaymentId, into: &buf)
            FfiConverterData.write(trustedRebalancePaymentId, into: &buf)
            FfiConverterUInt64.write(amountMsat, into: &buf)
            
        
        case let .rebalanceSuccessful(triggerPaymentId,trustedRebalancePaymentId,lnRebalancePaymentId,amountMsat,feeMsat):
            writeInt(&buf, Int32(8))
            FfiConverterTypePaymentId.write(triggerPaymentId, into: &buf)
            FfiConverterData.write(trustedRebalancePaymentId, into: &buf)
            FfiConverterData.write(lnRebalancePaymentId, into: &buf)
            FfiConverterUInt64.write(amountMsat, into: &buf)
            FfiConverterUInt64.write(feeMsat, into: &buf)
            
        
        case let .splicePending(channelId,userChannelId,counterpartyNodeId,newFundingTxo):
            writeInt(&buf, Int32(9))
            FfiConverterData.write(channelId, into: &buf)
            FfiConverterData.write(userChannelId, into: &buf)
            FfiConverterData.write(counterpartyNodeId, into: &buf)
            FfiConverterString.write(newFundingTxo, into: &buf)
            
        }
    }
}


