        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .outgoingLightningBolt12(paymentPreimage: try FfiConverterOptionData.read(from: &buf)
        )
        
        case 2: return .outgoingLightningBolt11(paymentPreimage: try FfiConverterOptionData.read(from: &buf)
        )
        
        case 3: return .outgoingOnChain(txid: try FfiConverterOptionData.read(from: &buf)
        )
        
        case 4: return .incomingOnChain(txid: try FfiConverterOptionData.read(from: &buf)
        )
        
        case 5: return .incomingLightning
        
        case 6: return .trustedInternal
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: PaymentType, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .outgoingLightningBolt12(paymentPreimage):
            writeInt(&buf, Int32(1))
            FfiConverterOptionData.write(paymentPreimage, into: &buf)
            
        
        case let .outgoingLightningBolt11(paymentPreimage):
            writeInt(&buf, Int32(2))
            FfiConverterOptionData.write(paymentPreimage, into: &buf)
            
        
        case let .outgoingOnChain(txid):
