        case let .incomingOnChain(txid):
            writeInt(&buf, Int32(4))
            FfiConverterOptionData.write(txid, into: &buf)
            
        
        case .incomingLightning:
            writeInt(&buf, Int32(5))
        
        
        case .trustedInternal:
